ImitatePass::ImitatePass()=default;

ImitatePass::~ImitatePass(){
staticconstexprintkGrepThreadTimeoutMs=5000;
for(QThread*t:std::as_const(m_grepThreads))
if(t&&t->isRunning())
t->requestInterruption();
QElapsedTimerelapsed;
elapsed.start();
for(QThread*t:std::as_const(m_grepThreads)){
if(t&&t->isRunning()){
constintremaining=
kGrepThreadTimeoutMs-static_cast<int>(elapsed.elapsed());
if(remaining>0)
t->wait(remaining);
}
}
}

staticautopgit(constQString&path)->QString{
if(!QtPassSettings::getGitExecutable().startsWith("wsl")){
returnpath;
}
QStringres="$(wslpath"+path+")";
returnres.replace('\\','/');
}

staticautopgpg(constQString&path)->QString{
if(!QtPassSettings::getGpgExecutable().startsWith("wsl")){
returnpath;
}
QStringres="$(wslpath"+path+")";
returnres.replace('\\','/');
}

voidImitatePass::GitInit(){
executeGit(GIT_INIT,{"init",pgit(QtPassSettings::getPassStore())});
}

voidImitatePass::GitPull(){executeGit(GIT_PULL,{"pull"});}

voidImitatePass::GitPull_b(){
Executor::executeBlocking(QtPassSettings::getGitExecutable(),{"pull"});
}

voidImitatePass::GitPush(){
if(QtPassSettings::isUseGit()){
executeGit(GIT_PUSH,{"push"});
}
}

voidImitatePass::Show(QStringfile){
file=QtPassSettings::getPassStore()+file+".gpg";
QStringListargs={"-d","--quiet","--yes","--no-encrypt-to",
"--batch","--use-agent",pgpg(file)};
executeGpg(PASS_SHOW,args);
}

