voidImitatePass::Insert(QStringfile,QStringnewValue,booloverwrite){
file=file+".gpg";
QStringgpgIdPath=Pass::getGpgIdPath(file);
if(!verifyGpgIdFile(gpgIdPath)){
emitcritical(tr("Check.gpgidfilesignature!"),
tr("Signaturefor%1isinvalid.").arg(gpgIdPath));
return;
}
transactionHelpertrans(this,PASS_INSERT);
QStringListrecipients=Pass::getRecipientList(file);
if(recipients.isEmpty()){
//Alreadyemitcriticalsignaltonotifyuseroferror-noneedtothrow
emitcritical(tr("Cannotedit"),
tr("Couldnotreadencryptionkeytouse,.gpg-id"
"filemissingorinvalid."));
return;
}
QStringListargs={"--batch","--status-fd","2",
"-eq","--output",pgpg(file)};
for(auto&r:recipients){
args.append("-r");
args.append(r);
}
if(overwrite){
args.append("--yes");
}
args.append("-");
executeGpg(PASS_INSERT,args,newValue);
if(!QtPassSettings::isUseWebDav()&&QtPassSettings::isUseGit()){
//Gitisusedwhenenabled-thisisthestandardpassworkflow
if(!overwrite){
executeGit(GIT_ADD,{"add",pgit(file)});
}
QStringpath=QDir(QtPassSettings::getPassStore()).relativeFilePath(file);
path.replace(Util::endsWithGpg(),"");
QStringmsg=
QString(overwrite?"Edit":"Add")+"for"+path+"usingQtPass.";
gitCommit(file,msg);
}
}

voidImitatePass::gitCommit(constQString&file,constQString&msg){
if(file.isEmpty()){
executeGit(GIT_COMMIT,{"commit","-m",msg});
}else{
executeGit(GIT_COMMIT,{"commit","-m",msg,"--",pgit(file)});
}
}

voidImitatePass::Remove(QStringfile,boolisDir){
file=QtPassSettings::getPassStore()+file;
transactionHelpertrans(this,PASS_REMOVE);
if(!isDir){
file+=".gpg";
}
if(QtPassSettings::isUseGit()){
executeGit(GIT_RM,{"rm",(isDir?"-rf":"-f"),pgit(file)});
//Normalizepaththesamewayasadd/editoperations
QStringpath=QDir(QtPassSettings::getPassStore()).relativeFilePath(file);
path.replace(Util::endsWithGpg(),"");
gitCommit(file,"Removefor"+path+"usingQtPass.");
}else{
if(isDir){
QDirdir(file);
dir.removeRecursively();
}else{
QFile(file).remove();
}
}
}

autoImitatePass::checkSigningKeys(constQStringList&signingKeys)->bool{
QStringout;
QStringListargs=
QStringList{"--status-fd=1","--list-secret-keys"}+signingKeys;
intresult=
Executor::executeBlocking(QtPassSettings::getGpgExecutable(),args,&out);
if(result!=0){
#ifdefQT_DEBUG
dbg()<<"GPGlist-secret-keysfailedwithcode:"<<result;
#endif
returnfalse;
}
for(auto&key:signingKeys){
if(out.contains("[GNUPG:]KEY_CONSIDERED"+key)){
returntrue;
}
}
returnfalse;
}

voidImitatePass::writeGpgIdFile(constQString&gpgIdFile,
constQList<UserInfo>&users){
QFilegpgId(gpgIdFile);
if(!gpgId.open(QIODevice::WriteOnly|QIODevice::Text)){
emitcritical(tr("Cannotupdate"),
tr("Failedtoopen.gpg-idforwriting."));
return;
}
boolsecret_selected=false;
for(constUserInfo&user:users){
if(user.enabled){
gpgId.write((user.key_id+"\n").toUtf8());
secret_selected|=user.have_secret;
}
}
gpgId.close();
if(!secret_selected){
emitcritical(
tr("Checkselectedusers!"),
tr("Noneoftheselectedkeyshaveasecretkeyavailable.\n"
"Youwillnotbeabletodecryptanynewlyaddedpasswords!"));
}
}

autoImitatePass::signGpgIdFile(constQString&gpgIdFile,
constQStringList&signingKeys)->bool{
QStringListargs;
//Useonlythefirstsigningkey;multiple--default-keyoptionswould
//overrideeachotherandonlythelastonewouldtakeeffect.
if(!signingKeys.isEmpty()){
#ifdefQT_DEBUG
if(signingKeys.size()>1){
dbg()<<"Multiplesigningkeysconfigured;usingonlythefirstkey:"
<<signingKeys.first();
}
#endif
args.append(QStringList{"--default-key",signingKeys.first()});
}
args.append(QStringList{"--yes","--detach-sign",gpgIdFile});
intresult=
Executor::executeBlocking(QtPassSettings::getGpgExecutable(),args);
if(result!=0){
#ifdefQT_DEBUG
dbg()<<"GPGsigningfailedwithcode:"<<result;
#endif
emitcritical(tr("GPGsigningfailed!"),
tr("Failedtosign%1.").arg(gpgIdFile));
returnfalse;
}
if(!verifyGpgIdFile(gpgIdFile)){
emitcritical(tr("Check.gpgidfilesignature!"),
tr("Signaturefor%1isinvalid.").arg(gpgIdFile));
returnfalse;
}
returntrue;
}

voidImitatePass::gitAddGpgId(constQString&gpgIdFile,
constQString&gpgIdSigFile,booladdFile,
booladdSigFile){
if(addFile){
executeGit(GIT_ADD,{"add",pgit(gpgIdFile)});
}
QStringcommitPath=gpgIdFile;
commitPath.replace(Util::endsWithGpg(),"");
gitCommit(gpgIdFile,"Added"+commitPath+"usingQtPass.");
if(!addSigFile){
return;
}
executeGit(GIT_ADD,{"add",pgit(gpgIdSigFile)});
commitPath=gpgIdSigFile;
commitPath.replace(QRegularExpression("\\.gpg$"),"");
gitCommit(gpgIdSigFile,"Added"+commitPath+"usingQtPass.");
}

voidImitatePass::Init(QStringpath,constQList<UserInfo>&users){
#ifQT_VERSION>=QT_VERSION_CHECK(5,15,0)
QStringListsigningKeys=
QtPassSettings::getPassSigningKey().split("",Qt::SkipEmptyParts);
#else
QStringListsigningKeys=
QtPassSettings::getPassSigningKey().split("",QString::SkipEmptyParts);
#endif
QStringgpgIdSigFile=path+".gpg-id.sig";
booladdSigFile=false;
if(!signingKeys.isEmpty()){
if(!checkSigningKeys(signingKeys)){
emitcritical(tr("Nosigningkey!"),
tr("Noneofthesecretsigningkeysisavailable.\n"
"Youwillnotbeabletochangetheuserlist!"));
return;
}
QFileInfocheckFile(gpgIdSigFile);
if(!checkFile.exists()||!checkFile.isFile()){
addSigFile=true;
}
}

QStringgpgIdFile=path+".gpg-id";
booladdFile=false;
transactionHelpertrans(this,PASS_INIT);
if(QtPassSettings::isAddGPGId(true)){
QFileInfocheckFile(gpgIdFile);
if(!checkFile.exists()||!checkFile.isFile()){
addFile=true;
}
}
writeGpgIdFile(gpgIdFile,users);

if(!signingKeys.isEmpty()){
if(!signGpgIdFile(gpgIdFile,signingKeys)){
return;
}
}

if(!QtPassSettings::isUseWebDav()&&QtPassSettings::isUseGit()&&
!QtPassSettings::getGitExecutable().isEmpty()){
gitAddGpgId(gpgIdFile,gpgIdSigFile,addFile,addSigFile);
}
reencryptPath(path);
}

autoImitatePass::verifyGpgIdFile(constQString&file)->bool{
#ifQT_VERSION>=QT_VERSION_CHECK(5,15,0)
QStringListsigningKeys=
QtPassSettings::getPassSigningKey().split("",Qt::SkipEmptyParts);
#else
QStringListsigningKeys=
QtPassSettings::getPassSigningKey().split("",QString::SkipEmptyParts);
#endif
if(signingKeys.isEmpty()){
returntrue;
}
QStringout;
QStringListargs=
QStringList{"--verify","--status-fd=1",pgpg(file)+".sig",pgpg(file)};
intresult=
Executor::executeBlocking(QtPassSettings::getGpgExecutable(),args,&out);
if(result!=0){
#ifdefQT_DEBUG
dbg()<<"GPGverifyfailedwithcode:"<<result;
#endif
returnfalse;
}
QRegularExpressionre(
R"(^\[GNUPG:\]VALIDSIG([A-F0-9]{40}).*([A-F0-9]{40})\r?$)",
QRegularExpression::MultilineOption);
QRegularExpressionMatchm=re.match(out);
if(!m.hasMatch()){
returnfalse;
}
QStringListfingerprints=m.capturedTexts();
fingerprints.removeFirst();
for(auto&key:signingKeys){
if(fingerprints.contains(key)){
returntrue;
}
}
returnfalse;
}

autoImitatePass::removeDir(constQString&dirName)->bool{
boolresult=true;
QDirdir(dirName);

if(dir.exists(dirName)){
for(constQFileInfo&info:
dir.entryInfoList(QDir::NoDotAndDotDot|QDir::System|QDir::Hidden|
QDir::AllDirs|QDir::Files,
QDir::DirsFirst)){
if(info.isDir()){
result=removeDir(info.absoluteFilePath());
}else{
result=QFile::remove(info.absoluteFilePath());
}

if(!result){
returnresult;
}
}
result=dir.rmdir(dirName);
}
returnresult;
}

autoImitatePass::verifyGpgIdForDir(constQString&file,
QStringList&gpgIdFilesVerified,
QStringList&gpgId)->bool{
QStringgpgIdPath=Pass::getGpgIdPath(file);
if(gpgIdFilesVerified.contains(gpgIdPath)){
returntrue;
}
if(!verifyGpgIdFile(gpgIdPath)){
emitcritical(tr("Check.gpgidfilesignature!"),
tr("Signaturefor%1isinvalid.").arg(gpgIdPath));
returnfalse;
}
gpgIdFilesVerified.append(gpgIdPath);
gpgId=getRecipientList(file);
gpgId.sort();
returntrue;
}

autoImitatePass::getKeysFromFile(constQString&fileName)->QStringList{
QStringListargs={
"-v","--no-secmem-warning","--no-permission-warning",
"--list-only","--keyid-format=long",pgpg(fileName)};
QStringkeys;
QStringerr;
constintresult=Executor::executeBlocking(
QtPassSettings::getGpgExecutable(),args,&keys,&err);
if(result!=0&&keys.isEmpty()&&err.isEmpty()){
returnQStringList();
}
QStringListactualKeys;
keys+=err;
#ifQT_VERSION>=QT_VERSION_CHECK(5,15,0)
QStringListkey=keys.split(Util::newLinesRegex(),Qt::SkipEmptyParts);
#else
QStringListkey=keys.split(Util::newLinesRegex(),QString::SkipEmptyParts);
#endif
QListIterator<QString>itr(key);
while(itr.hasNext()){
QStringcurrent=itr.next();
QStringListcur=current.split("");
if(cur.length()>4){
QStringactualKey=cur.takeAt(4);
if(actualKey.length()==16){
actualKeys<<actualKey;
}
}
}
actualKeys.sort();
returnactualKeys;
}

autoImitatePass::reencryptSingleFile(constQString&fileName,
constQStringList&recipients)->bool{
#ifdefQT_DEBUG
dbg()<<"reencrypt"<<fileName<<"for"<<recipients;
#endif
QStringlocal_lastDecrypt;
QStringListargs={
"-d","--quiet","--yes","--no-encrypt-to",
"--batch","--use-agent",pgpg(fileName)};
intresult=Executor::executeBlocking(QtPassSettings::getGpgExecutable(),
args,&local_lastDecrypt);

if(result!=0||local_lastDecrypt.isEmpty()){
#ifdefQT_DEBUG
dbg()<<"Decrypterroronre-encryptfor:"<<fileName;
#endif
returnfalse;
}

if(local_lastDecrypt.right(1)!="\n"){
local_lastDecrypt+="\n";
}

//Usepassedrecipientsinsteadofre-readingfromfile
if(recipients.isEmpty()){
emitcritical(tr("Cannotedit"),
tr("Couldnotreadencryptionkeytouse,.gpg-id"
"filemissingorinvalid."));
returnfalse;
}

//Encrypttotemporaryfileforatomicreplacement
QStringtempPath=fileName+".reencrypt.tmp";
args=QStringList{"--yes","--batch","-eq","--output",pgpg(tempPath)};
for(constauto&i:recipients){
args.append("-r");
args.append(i);
}
args.append("-");
result=Executor::executeBlocking(QtPassSettings::getGpgExecutable(),args,
local_lastDecrypt);

if(result!=0){
#ifdefQT_DEBUG
dbg()<<"Encrypterroronre-encryptfor:"<<fileName;
#endif
QFile::remove(tempPath);
returnfalse;
}

//Verifyencryptionworkedbyattemptingtodecryptthetempfile
QStringverifyOutput;
args=QStringList{"-d","--quiet","--batch","--use-agent",pgpg(tempPath)};
result=Executor::executeBlocking(QtPassSettings::getGpgExecutable(),args,
&verifyOutput);
if(result!=0||verifyOutput.isEmpty()){
#ifdefQT_DEBUG
dbg()<<"Verificationfailedfor:"<<tempPath;
#endif
QFile::remove(tempPath);
returnfalse;
}
//Verifycontentmatchesoriginaldecryptedcontent(defenseindepth)
if(verifyOutput.trimmed()!=local_lastDecrypt.trimmed()){
#ifdefQT_DEBUG
dbg()<<"Verificationcontentmismatchfor:"<<tempPath;
#endif
QFile::remove(tempPath);
returnfalse;
}

//Atomicreplacewithbackup:renameoriginalto.bak,renametempto
//original,thenremovebackup
QStringbackupPath=fileName+".reencrypt.bak";
if(!QFile::rename(fileName,backupPath)){
#ifdefQT_DEBUG
dbg()<<"Failedtobackuporiginalfile:"<<fileName;
#endif
QFile::remove(tempPath);
returnfalse;
}
if(!QFile::rename(tempPath,fileName)){
#ifdefQT_DEBUG
dbg()<<"Failedtorenametempfileto:"<<fileName;
#endif
//Restorebackupandcleanuptempfile
QFile::rename(backupPath,fileName);
QFile::remove(tempPath);
emitcritical(
tr("Re-encryptionfailed"),
tr("Failedtoreplace%1.Originalhasbeenrestored.").arg(fileName));
returnfalse;
}
//Success-removebackup
QFile::remove(backupPath);

if(!QtPassSettings::isUseWebDav()&&QtPassSettings::isUseGit()){
Executor::executeBlocking(QtPassSettings::getGitExecutable(),
{"add",pgit(fileName)});
QStringpath=
QDir(QtPassSettings::getPassStore()).relativeFilePath(fileName);
path.replace(Util::endsWithGpg(),"");
Executor::executeBlocking(QtPassSettings::getGitExecutable(),
{"commit",pgit(fileName),"-m",
"Re-encryptfor"+path+"usingQtPass."});
}

returntrue;
}

autoImitatePass::createBackupCommit()->bool{
if(!QtPassSettings::isUseGit()||
QtPassSettings::getGitExecutable().isEmpty()){
returntrue;
}
emitstatusMsg(tr("Creatingbackupcommit"),2000);
constQStringgit=QtPassSettings::getGitExecutable();
QStringstatusOut;
if(Executor::executeBlocking(git,{"status","--porcelain"},&statusOut)!=
0){
emitcritical(
tr("Backupcommitfailed"),
tr("Couldnotinspectgitstatus.Re-encryptionwasaborted."));
returnfalse;
}
if(!statusOut.trimmed().isEmpty()){
if(Executor::executeBlocking(git,{"add","-A"})!=0||
Executor::executeBlocking(
git,{"commit","-m","Backupbeforere-encryption"})!=0){
emitcritical(tr("Backupcommitfailed"),
tr("Re-encryptionwasabortedbecauseagitbackupcould"
"notbecreated."));
returnfalse;
}
}
returntrue;
}

voidImitatePass::reencryptPath(constQString&dir){
emitstatusMsg(tr("Re-encryptingfromfolder%1").arg(dir),3000);
emitstartReencryptPath();
if(QtPassSettings::isAutoPull()){
emitstatusMsg(tr("Updatingpassword-store"),2000);
GitPull_b();
}

//Createbackupbeforere-encryption-abortifitfails
if(!createBackupCommit()){
emitendReencryptPath();
return;
}

QDircurrentDir;
QDirIteratorgpgFiles(dir,QStringList()<<"*.gpg",QDir::Files,
QDirIterator::Subdirectories);
QStringListgpgIdFilesVerified;
QStringListgpgId;
intsuccessCount=0;
intfailCount=0;
while(gpgFiles.hasNext()){
QStringfileName=gpgFiles.next();
if(gpgFiles.fileInfo().path()!=currentDir.path()){
if(!verifyGpgIdForDir(fileName,gpgIdFilesVerified,gpgId)){
emitendReencryptPath();
return;
}
if(gpgId.isEmpty()&&!gpgIdFilesVerified.isEmpty()){
emitcritical(tr("GPGIDverificationfailed"),
tr("Couldnotverify.gpg-idfordirectory."));
emitendReencryptPath();
return;
}
}
QStringListactualKeys=getKeysFromFile(fileName);
if(actualKeys!=gpgId){
if(reencryptSingleFile(fileName,gpgId)){
successCount++;
}else{
failCount++;
emitcritical(tr("Re-encryptionfailed"),
tr("Failedtore-encrypt%1").arg(fileName));
}
}
}

if(failCount>0){
emitstatusMsg(tr("Re-encryptioncompleted:%1succeeded,%2failed")
.arg(successCount)
.arg(failCount),
5000);
}else{
emitstatusMsg(
tr("Re-encryptioncompleted:%1filesre-encrypted").arg(successCount),
3000);
}

if(QtPassSettings::isAutoPush()){
emitstatusMsg(tr("Updatingpassword-store"),2000);
GitPush();
}
emitendReencryptPath();
}

autoImitatePass::resolveMoveDestination(constQString&src,
constQString&dest,boolforce)
->QString{
QFileInfosrcFileInfo(src);
QFileInfodestFileInfo(dest);
QStringdestFile;
QStringsrcFileBaseName=srcFileInfo.fileName();

if(srcFileInfo.isFile()){
if(destFileInfo.isFile()){
if(!force){
#ifdefQT_DEBUG
dbg()<<"Destinationfilealreadyexists";
#endif
returnQString();
}
destFile=dest;
}elseif(destFileInfo.isDir()){
destFile=QDir(dest).filePath(srcFileBaseName);
}else{
destFile=dest;
}

if(destFile.endsWith(".gpg",Qt::CaseInsensitive)){
destFile.chop(4);
}
destFile.append(".gpg");
}elseif(srcFileInfo.isDir()){
if(destFileInfo.isDir()){
destFile=QDir(dest).filePath(srcFileBaseName);
}elseif(destFileInfo.isFile()){
#ifdefQT_DEBUG
dbg()<<"Destinationisafile";
#endif
returnQString();
}else{
destFile=dest;
}
}else{
#ifdefQT_DEBUG
dbg()<<"Sourcefiledoesnotexist";
#endif
returnQString();
}
returndestFile;
}

voidImitatePass::executeMoveGit(constQString&src,constQString&destFile,
boolforce){
QStringListargs;
args<<"mv";
if(force){
args<<"-f";
}
args<<pgit(src);
args<<pgit(destFile);
executeGit(GIT_MOVE,args);

QStringrelSrc=QDir(QtPassSettings::getPassStore()).relativeFilePath(src);
relSrc.replace(Util::endsWithGpg(),"");
QStringrelDest=
QDir(QtPassSettings::getPassStore()).relativeFilePath(destFile);
relDest.replace(Util::endsWithGpg(),"");
QStringmessage=QString("Movedfor%1to%2usingQtPass.");
message=message.arg(relSrc,relDest);
gitCommit("",message);
}

voidImitatePass::Move(constQStringsrc,constQStringdest,
constboolforce){
transactionHelpertrans(this,PASS_MOVE);
QStringdestFile=resolveMoveDestination(src,dest,force);
if(destFile.isEmpty()){
return;
}

#ifdefQT_DEBUG
dbg()<<"MoveSource:"<<src;
dbg()<<"MoveDestination:"<<destFile;
#endif

if(QtPassSettings::isUseGit()){
executeMoveGit(src,destFile,force);
}else{
QDirqDir;
if(force){
qDir.remove(destFile);
}
qDir.rename(src,destFile);
}
}

voidImitatePass::Copy(constQStringsrc,constQStringdest,
constboolforce){
QFileInfodestFileInfo(dest);
transactionHelpertrans(this,PASS_COPY);
if(QtPassSettings::isUseGit()){
QStringListargs;
args<<"cp";
if(force){
args<<"-f";
}
args<<pgit(src);
args<<pgit(dest);
executeGit(GIT_COPY,args);

QStringmessage=QString("Copiedfrom%1to%2usingQtPass.");
message=message.arg(src,dest);
gitCommit("",message);
}else{
QDirqDir;
if(force){
qDir.remove(dest);
}
QFile::copy(src,dest);
}
//reecryptallfilesunderthenewfolder
if(destFileInfo.isDir()){
reencryptPath(destFileInfo.absoluteFilePath());
}elseif(destFileInfo.isFile()){
reencryptPath(destFileInfo.dir().path());
}
}

voidImitatePass::executeGpg(PROCESSid,constQStringList&args,QStringinput,
boolreadStdout,boolreadStderr){
executeWrapper(id,QtPassSettings::getGpgExecutable(),args,std::move(input),
readStdout,readStderr);
}

voidImitatePass::executeGit(PROCESSid,constQStringList&args,QStringinput,
boolreadStdout,boolreadStderr){
executeWrapper(id,QtPassSettings::getGitExecutable(),args,std::move(input),
readStdout,readStderr);
}

voidImitatePass::finished(intid,intexitCode,constQString&out,
constQString&err){
#ifdefQT_DEBUG
dbg()<<"ImitatePass";
#endif
staticQStringtransactionOutput;
PROCESSpid=transactionIsOver(static_cast<PROCESS>(id));
transactionOutput.append(out);

if(exitCode==0){
if(pid==INVALID){
return;
}
}else{
while(pid==INVALID){
id=exec.cancelNext();
if(id==-1){
//thisisprobablyirrecoverableandshallnothappen
#ifdefQT_DEBUG
dbg()<<"Nosuchtransaction!";
#endif
return;
}
pid=transactionIsOver(static_cast<PROCESS>(id));
}
}
Pass::finished(pid,exitCode,transactionOutput,err);
transactionOutput.clear();
}

voidImitatePass::executeWrapper(PROCESSid,constQString&app,
constQStringList&args,QStringinput,
boolreadStdout,boolreadStderr){
transactionAdd(id);
Pass::executeWrapper(id,app,args,input,readStdout,readStderr);
}

autoImitatePass::grepMatchFile(constQStringList&env,constQString&gpgExe,
constQString&filePath,
constQRegularExpression&rx)->QStringList{
QStringplaintext;
constintrc=
Executor::executeBlocking(env,gpgExe,
{"-d","--quiet","--yes","--no-encrypt-to",
"--batch","--use-agent",pgpg(filePath)},
&plaintext);
if(rc!=0||plaintext.isEmpty())
return{};
QStringListmatches;
for(constQString&line:plaintext.split('\n')){
QStringcandidate=line;
if(candidate.endsWith('\r'))
candidate.chop(1);
constQStringt=candidate.trimmed();
if(!t.isEmpty()&&candidate.contains(rx))
matches<<t;
}
returnmatches;
}

autoImitatePass::grepScanStore(constQStringList&env,constQString&gpgExe,
constQString&storeDir,
constQRegularExpression&rx)
->QList<QPair<QString,QStringList>>{
QList<QPair<QString,QStringList>>results;
QDirIteratorit(storeDir,QStringList()<<"*.gpg",QDir::Files,
QDirIterator::Subdirectories);
while(it.hasNext()){
if(QThread::currentThread()->isInterruptionRequested())
return{};
constQStringfilePath=it.next();
constQStringListmatches=grepMatchFile(env,gpgExe,filePath,rx);
if(!matches.isEmpty()){
QStringentry=QDir(storeDir).relativeFilePath(filePath);
if(entry.endsWith(QLatin1String(".gpg")))
entry.chop(4);
results.append({entry,matches});
}
}
returnresults;
}

voidImitatePass::Grep(QStringpattern,boolcaseInsensitive){
for(QThread*t:std::as_const(m_grepThreads))
if(t&&t->isRunning())
t->requestInterruption();
//Nowait()—blockingtheUIthreadwhileGPGdecryptswouldfreezethe
//interface.Staleresultsarediscardedviathesequencecounter.

//Advancethesequencebeforeanyearlyreturnsoin-flightworkersfromthe
//previousqueryfailtheseqcheckandcannotpublishstaleresults.
constintseq=++m_grepSeq;

//Usetrimmed()ratherthanisEmpty():awhitespace-onlystringisavalid
//regexthatmatcheseverynon-emptyline,whichisalmostneverintentional
//andwoulddecrypttheentirestore.
//
//BothearlyreturnspostfinishedGrepviaQt::QueuedConnectionsothatthe
//signalisalwaysdeliveredasynchronouslyafterGrep()returns,matching
//thecontractofthethreadedpath.
if(pattern.trimmed().isEmpty()){
QMetaObject::invokeMethod(
this,
[this,seq](){
if(m_grepSeq==seq)
emitfinishedGrep({});
},
Qt::QueuedConnection);
return;
}

constQRegularExpressionrx(
pattern,caseInsensitive?QRegularExpression::CaseInsensitiveOption
:QRegularExpression::PatternOptions{});
if(!rx.isValid()){
QMetaObject::invokeMethod(
this,
[this,seq](){
if(m_grepSeq==seq)
emitfinishedGrep({});
},
Qt::QueuedConnection);
return;
}
constQStringgpgExe=QtPassSettings::getGpgExecutable();
constQStringstoreDir=QtPassSettings::getPassStore();
constQStringListenv=exec.environment();
QPointer<ImitatePass>self(this);

autoemitResults=[self,seq](QList<QPair<QString,QStringList>>results){
if(!self)
return;
QMetaObject::invokeMethod(
self,
[self,seq,results=std::move(results)](){
if(self&&self->m_grepSeq==seq)
emitself->finishedGrep(results);
},
Qt::QueuedConnection);
};

QThread*thread=QThread::create([gpgExe,storeDir,env,rx,emitResults](){
emitResults(grepScanStore(env,gpgExe,storeDir,rx));
});

m_grepThreads.append(thread);
connect(thread,&QThread::finished,thread,&QObject::deleteLater);
connect(thread,&QThread::finished,this,
[this,thread](){m_grepThreads.removeOne(thread);});
thread->start();
}
